func (s *RateLimiter) Allow(key string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	now := time.Now()
	bucket, ok := s.buckets[key]
	if !ok {
		s.buckets[key] = &bucket{tokens: s.rate - 1, last: now}
		return true
	}

	elapsed := now.Sub(bucket.last).Seconds()
	bucket.tokens += elapsed * float64(s.rate)
	if bucket.tokens > float64(s.burst) {
		bucket.tokens = float64(s.burst)
	}
	bucket.last = now

	if bucket.tokens >= 1 {
		bucket.tokens--
		return true
	}
	return false
}
